import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { theme } from '../styles/theme';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const addToast = useToast();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return addToast('Please enter details.', 'error');
    setLoading(true);
    try {
      await login(email, password);
      addToast('Welcome back to the kitchen!', 'success');
      navigate('/generate'); 
    } catch (err) { addToast('Could not log in.', 'error'); } 
    finally { setLoading(false); }
  };

  const styles = {
    container: { minHeight: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem' },
    card: { 
        width: '100%', maxWidth: '400px', padding: '3rem', 
        backgroundColor: '#FFF', 
        borderRadius: '24px', 
        border: '3px solid #5C4033', 
        boxShadow: '8px 8px 0px rgba(92,64,51,0.2)' 
    },
    title: { fontFamily: theme.fonts.header, fontSize: '3rem', color: theme.colors.text.main, marginBottom: '2rem', textAlign: 'center' },
    
    // WRAPPER FOR POSITIONING
    inputGroup: { position: 'relative', marginBottom: '1.2rem', width: '100%' },

    input: { 
        width: '100%', 
        padding: '1rem 3rem 1rem 1rem', // Space for icon
        backgroundColor: '#FFFBEB', 
        border: '2px solid #E6DACD', 
        borderRadius: '12px', 
        color: theme.colors.text.main, 
        fontSize: '1rem', 
        outline: 'none',
        boxSizing: 'border-box' // FIX: Prevents overflow
    },
    toggleBtn: { 
        position: 'absolute', 
        right: '15px', 
        top: '50%', 
        transform: 'translateY(-50%)', 
        background: 'none', 
        border: 'none', 
        color: theme.colors.text.muted, 
        cursor: 'pointer', 
        display: 'flex', 
        alignItems: 'center',
        zIndex: 10,
        fontSize: '1.2rem'
    },
    button: { 
        width: '100%', padding: '1rem', marginTop: '0.5rem', 
        backgroundColor: theme.colors.primary, 
        color: '#FFF', border: '3px solid #5C4033', 
        borderRadius: '12px', fontFamily: theme.fonts.header, fontSize: '1.5rem',
        cursor: 'pointer', boxShadow: '4px 4px 0px #5C4033'
    },
  };

  return (
    <div style={styles.container}>
      <style>{`
        input::-ms-reveal,
        input::-ms-clear { display: none; }
      `}</style>

      <div style={styles.card}>
        <h2 style={styles.title}>Login</h2>
        <form onSubmit={handleSubmit}>
          
          <div style={styles.inputGroup}>
            <input 
                type="email" 
                placeholder="Email Address" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                style={styles.input} 
            />
          </div>
          
          <div style={styles.inputGroup}>
            <input 
                type={showPass ? "text" : "password"} 
                placeholder="Password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                style={styles.input} 
            />
            <button type="button" onClick={() => setShowPass(!showPass)} style={styles.toggleBtn}>
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button type="submit" style={styles.button} disabled={loading}>{loading ? 'Opening Door...' : 'Enter Kitchen'}</button>
        </form>
        <div style={{textAlign: 'center', marginTop: '1.5rem'}}>
            <Link to="/register" style={{color: theme.colors.text.muted, fontWeight: 'bold'}}>New here? Sign Up</Link>
        </div>
      </div>
    </div>
  );
};
export default LoginPage;
